import { useState } from "react";
import { ToastContainer, toast } from "react-toastify";
import "react-toastify/dist/ReactToastify.css";

import "./changepasswordpage.css";

function ChangePasswordPage() {
    let [firstinput, changenameinput] = useState("");
    let [secondinput, changepasswordinput] = useState("");

    async function func1() {
        if (firstinput.length <= 6) {
            toast.warning("Password must be more than 6 characters");
            return;
        }

        if (firstinput !== secondinput) {
            toast.error("Passwords do not match");
            return;
        }

        await fetch("http://localhost:5000/changepassword", {
            method: "POST",
            headers: {"Content-Type":"application/json"},
            body: JSON.stringify({
                token: new URLSearchParams(window.location.search).get("token"),
                newpassword: firstinput
            })
        });

        toast.success("Password changed successfully");
    }

    return (
        <div className="change-container">
            <div className="change-card">
                <h1>Reset Password</h1>

                <input 
                    value={firstinput}
                    onChange={(e) => changenameinput(e.target.value)} 
                    type="password" 
                    placeholder="New Password" 
                />

                <input 
                    value={secondinput}
                    onChange={(e) => changepasswordinput(e.target.value)} 
                    type="password" 
                    placeholder="Confirm Password" 
                />

                <button onClick={func1}>
                    Change Password
                </button>
            </div>

            <ToastContainer
                position="top-center"
                autoClose={2500}
                theme="dark"
                limit={3}
            />
        </div>
    );
}

export default ChangePasswordPage;
